  let policy: Schedule.Schedule<unknown, ZynkError, never>

  switch (backoff.kind) {
    case "none":
      policy = Schedule.recurs(0) as unknown as Schedule.Schedule<
        unknown,
        ZynkError,
        never
      >
      break
    case "fixed":
      policy = Schedule.fixed(backoff.delay) as unknown as Schedule.Schedule<
        unknown,
        ZynkError,
        never
      >
      break
    case "spaced":
      policy = Schedule.spaced(backoff.delay) as unknown as Schedule.Schedule<
        unknown,
        ZynkError,
        never
      >
      break
    case "exponential": {
      let exp = Schedule.exponential(
        backoff.base,
        backoff.factor,
      ) as unknown as Schedule.Schedule<unknown, ZynkError, never>
      if (backoff.max !== undefined) {
        exp = Schedule.intersect(exp, Schedule.spaced(backoff.max))
      }
      policy = exp
      break
    }
  }

  const times = options.times ?? DEFAULT_RETRY.times ?? 0
  policy = Schedule.intersect(policy, Schedule.recurs(times))

  if (options.jitter ?? DEFAULT_RETRY.jitter) {
    policy = Schedule.jittered(policy)
  }

  const whileFn = options.while ?? DEFAULT_RETRY.while
  const untilFn = options.until
