const buildHeaders = (
  base: Readonly<Record<string, string>> | undefined,
  call: Readonly<Record<string, string>> | undefined,
  contentType?: string,
): Record<string, string> => {
  const headers: Record<string, string> = {
    ...(base ?? {}),
    ...(call ?? {}),
  }
  if (
    contentType &&
    !("Content-Type" in headers) &&
    !("content-type" in headers)
  ) {
    headers["Content-Type"] = contentType
  }
  return headers
}

const joinUrl = (base: string, path: string): string => {
  const trimmedBase = base.replace(/\/$/, "")
  const trimmedPath = path.startsWith("/") ? path : `/${path}`
  return `${trimmedBase}${trimmedPath}`
}

const linkSignals = (
  caller: AbortSignal | undefined,
  inner: AbortController,
): (() => void) | undefined => {
  if (!caller) return undefined
  if (caller.aborted) {
    inner.abort()
    return undefined
  }
  const onAbort = () => inner.abort()
  caller.addEventListener("abort", onAbort, { once: true })
  return () => caller.removeEventListener("abort", onAbort)
}

const wrapNetworkError = (url: string, cause: unknown): ZynkError => {
  if (cause instanceof DOMException && cause.name === "AbortError") {
    return new ZynkAbortError({ url })
  }
  if (
    typeof cause === "object" &&
    cause !== null &&
    "name" in cause &&
    (cause as { name?: string }).name === "AbortError"
  ) {
    return new ZynkAbortError({ url })
  }
  return new ZynkNetworkError({ url, cause })
}

const safeJsonParse = (
  text: string,
): {
  result?: unknown
  code?: string
  message?: string
  details?: unknown
  error?: string
} => {
  try {
    return JSON.parse(text)
  } catch {
    return { message: text }
  }
}

const camelToSnake = (key: string): string =>
  key.replace(/[A-Z]/g, (m, i) => (i === 0 ? m.toLowerCase() : `_${m.toLowerCase()}`))

const toSnakeCaseKeys = (value: unknown): unknown => {
  if (Array.isArray(value)) return value.map(toSnakeCaseKeys)
  if (value !== null && typeof value === "object") {
    const out: Record<string, unknown> = {}
    for (const [key, v] of Object.entries(value as Record<string, unknown>)) {
      out[camelToSnake(key)] = toSnakeCaseKeys(v)
    }
    return out
  }
  return value
}

