interface OpenedStream {
  readonly response: Response
  readonly controller: AbortController
  readonly unlink: (() => void) | undefined
}

export const callChannel = <A, I>(
  command: string,
  args: unknown,
  itemSchema: Schema.Schema<A, I>,
  options?: CallOptions,
): Stream.Stream<A, ZynkError, ZynkClient> =>
  Stream.unwrap(
    Effect.gen(function* () {
      const client = yield* ZynkClient
      const url = joinUrl(client.baseUrl, `/channel/${command}`)
      const timeout = options?.timeout ?? client.timeout

      const open: Effect.Effect<OpenedStream, ZynkError> = Effect.gen(
        function* () {
          const controller = new AbortController()
          const unlink = linkSignals(options?.signal, controller)

          const response = yield* Effect.tryPromise({
            try: () =>
              client.resolvedFetch(url, {
                method: "POST",
                headers: buildHeaders(
                  client.headers,
                  options?.headers,
                  "application/json",
                ),
                body: JSON.stringify(toSnakeCaseKeys(args) ?? {}),
                signal: controller.signal,
              }),
            catch: (cause) => {
              unlink?.()
              return wrapNetworkError(url, cause)
            },
          })

          if (!response.ok) {
            unlink?.()
            const text = yield* Effect.tryPromise({
              try: () => response.text(),
              catch: () =>
                new ZynkNetworkError({ url, cause: "stream open" }),
            })
            const payload = text ? safeJsonParse(text) : {}
            return yield* Effect.fail(
              new ZynkHttpError({
                url,
                status: response.status,
                statusText: response.statusText,
                code: payload.code,
                message: payload.message,
                details: payload.details,
              }),
            )
          }

          if (!response.body) {
            unlink?.()
            return yield* Effect.fail(
              new ZynkStreamError({
                url,
                code: "NO_STREAM",
                message: "Response has no body",
              }),
            )
          }

          return { response, controller, unlink }
        },
      )

      const opened: OpenedStream = yield* (timeout
        ? open.pipe(
            Effect.timeoutFail({
              duration: timeout,
              onTimeout: () =>
                new ZynkTimeoutError({
                  url,
                  durationMs: Duration.toMillis(Duration.decode(timeout)),
                }),
            }),
          )
        : open)

      return makeSseStream(url, opened.response.body!, itemSchema).pipe(
        Stream.ensuring(
          Effect.sync(() => {
            opened.unlink?.()
            opened.controller.abort()
          }),
        ),
      )
    }),
  )

const makeSseStream = <A, I>(
  url: string,
  body: ReadableStream<Uint8Array>,
  itemSchema: Schema.Schema<A, I>,
): Stream.Stream<A, ZynkError> =>
  Stream.async<A, ZynkError>((emit) => {
    const reader = body.getReader()
    const decoder = new TextDecoder()
    let buffer = ""
    let stopped = false

    const stop = async () => {
      if (stopped) return
      stopped = true
      try {
        await reader.cancel()
      } catch {
        // ignore
      }
    }

    const pump = async () => {
      try {
        while (!stopped) {
          const { done, value } = await reader.read()
          if (done) {
            void emit.end()
            return
          }
          buffer += decoder.decode(value, { stream: true })
          const events = buffer.split("\n\n")
          buffer = events.pop() ?? ""
          for (const block of events) {
            if (!block.trim()) continue
            let eventType = "message"
            let eventData = ""
            for (const line of block.split("\n")) {
              if (line.startsWith("event: ")) eventType = line.slice(7)
              else if (line.startsWith("data: ")) eventData = line.slice(6)
            }
            if (eventType === "error") {
              const parsed = eventData ? safeJsonParse(eventData) : {}
              void emit.fail(
                new ZynkStreamError({
                  url,
                  code:
                    typeof parsed.code === "string"
                      ? parsed.code
                      : "STREAM_ERROR",
                  message:
                    typeof parsed.message === "string"
                      ? parsed.message
                      : parsed.error ?? "stream error",
                  details: parsed.details,
                }),
              )
              return
            }
            if (eventType === "close") {
              void emit.end()
              return
            }
            if (eventData) {
              const parsed = safeJsonParse(eventData)
              const payload =
                parsed && typeof parsed === "object" && !Array.isArray(parsed)
                  ? { event: eventType, ...parsed }
                  : parsed
              try {
                const decoded = await Effect.runPromise(
                  Schema.decodeUnknown(itemSchema)(payload) as Effect.Effect<A>,
                )
                void emit.single(decoded)
              } catch (cause) {
                void emit.fail(
                  new ZynkDecodeError({ url, cause }),
                )
                return
              }
            }
          }
        }
      } catch (cause) {
        if (!stopped) {
          void emit.fail(wrapNetworkError(url, cause))
        }
      }
    }

    void pump()

    return Effect.sync(() => {
      void stop()
    })
  })

// ---------------------------------------------------------------------------
// Uploads
// ---------------------------------------------------------------------------

export interface UploadProgressEvent {
  readonly loaded: number
  readonly total: number
  readonly percentage: number
}

export interface UploadOptions extends CallOptions {
  readonly onProgress?: (event: UploadProgressEvent) => void
}

export const callUpload = <A, I>(
  handler: string,
  files: ReadonlyArray<File>,
  args: Record<string, unknown>,
  responseSchema: Schema.Schema<A, I>,
  options?: UploadOptions,
): Effect.Effect<A, ZynkError, ZynkClient> =>
  Effect.gen(function* () {
    const client = yield* ZynkClient
    const url = joinUrl(client.baseUrl, `/upload/${handler}`)
    const timeout = options?.timeout ?? client.timeout
    const retry = mergeRetry(client.retry, options?.retry)

    const perform = Effect.async<A, ZynkError>((resume) => {
      const xhr = new XMLHttpRequest()
      let aborted = false
      const onCallerAbort = () => {
        aborted = true
        try {
          xhr.abort()
        } catch {
          // ignore
        }
      }
      if (options?.signal) {
        if (options.signal.aborted) {
          onCallerAbort()
        } else {
          options.signal.addEventListener("abort", onCallerAbort, {
            once: true,
          })
        }
      }
      const unlink = () => {
        options?.signal?.removeEventListener("abort", onCallerAbort)
      }

      const formData = new FormData()
      for (const file of files) {
        formData.append("files", file)
      }
      formData.append("_args", JSON.stringify(toSnakeCaseKeys(args) ?? {}))

      if (options?.onProgress) {
        xhr.upload.onprogress = (event) => {
          if (event.lengthComputable) {
            options.onProgress!({
              loaded: event.loaded,
              total: event.total,
              percentage: Math.round((event.loaded / event.total) * 100),
            })
          }
        }
      }

      xhr.onload = () => {
        unlink()
        const text = xhr.responseText
        const payload = text ? safeJsonParse(text) : {}
        if (xhr.status >= 200 && xhr.status < 300) {
          Effect.runPromiseExit(
            Schema.decodeUnknown(responseSchema)(payload.result) as Effect.Effect<A, unknown>,
          ).then((exit) => {
            if (exit._tag === "Success") {
              resume(Effect.succeed(exit.value))
            } else {
              resume(
                Effect.fail(
                  new ZynkDecodeError({ url, cause: exit.cause }),
                ),
              )
            }
          })
        } else {
          resume(
            Effect.fail(
              new ZynkUploadError({
                handler,
                status: xhr.status,
                code: payload.code,
                message:
                  payload.message ??
                  `Upload failed with status ${xhr.status}`,
                details: payload.details,
              }),
            ),
          )
        }
      }
      xhr.onerror = () => {
        unlink()
        if (aborted) {
          resume(Effect.fail(new ZynkAbortError({ url })))
        } else {
          resume(
            Effect.fail(
              new ZynkUploadError({
                handler,
                message: "Upload network error",
              }),
            ),
          )
        }
      }
      xhr.onabort = () => {
        unlink()
        resume(Effect.fail(new ZynkAbortError({ url })))
      }

      const headers = buildHeaders(client.headers, options?.headers)
      xhr.open("POST", url)
      for (const [key, value] of Object.entries(headers)) {
        if (key.toLowerCase() === "content-type") continue
        xhr.setRequestHeader(key, value)
      }
      xhr.send(formData)

      return Effect.sync(() => {
        try {
          xhr.abort()
        } catch {
          // ignore
        }
      })
    })

    const withTimeout = timeout
      ? perform.pipe(
          Effect.timeoutFail({
            duration: timeout,
            onTimeout: () =>
              new ZynkTimeoutError({
                url,
                durationMs: Duration.toMillis(Duration.decode(timeout)),
              }),
          }),
        )
      : perform

    return yield* withTimeout.pipe(Effect.retry(buildSchedule(retry)))
  })

